import { applyExpressionValueForParser } from "./parser-utils";
import { Scale } from "../scale/scale-component";
import { NUMERIC_DATATYPE, TIME_DATATYPE } from "../core/datatype-constants";
import { mergeJSON } from "../utils/zcutils";

export function createScaleComponetForParser(scaleConf, chart){
    let _parserConf = scaleConf,
        parser_expression_val = applyExpressionValueForParser(_parserConf, chart.viewFlow);

        if(_parserConf.extend){
            let columnInfo = chart.dataset.columnMappedByName[scaleConf.column];
            let defaultParser = defaultDomainOperator(columnInfo);
            _parserConf = mergeJSON(defaultParser, _parserConf, true, true, true);
        }

        if(_parserConf){
            parser_expression_val.map(d => {
                _parserConf[d[0]] = d[1];
            })
        }
        var newScaleComp1 = new Scale(null, 0, _parserConf, chart);
        let newScaleObj = newScaleComp1.getScale();

        return newScaleObj
}

function defaultDomainOperator(column){
    let domainOperators = {};
    if(column.datatype == NUMERIC_DATATYPE || column.datatype == TIME_DATATYPE){
        domainOperators.extremes = [{
            "_type": "extremesByData",
            "indices": [column.dataindex]
        }]
    }else{
        domainOperators.categories = {
            "indices": [column.dataindex]
        }
    }

    return {
        "domain": {
            "operators": domainOperators
        }
    }
    
}